#include <stdio.h>
int main() {
    int N;
    scanf("%d", &N);
    int inv[N], perm[N];
    for (int i = 0; i < N; i++) {
        scanf("%d", &inv[i]);
    }
    for (int i = 1; i <= N; i++) {
        int pos = 0;
        for (int j = 0; j < N; j++) {
            if (perm[j] == 0) {
                int count = 0;
                for (int k = j + 1; k < N; k++) {
                    if (perm[k] != 0 && perm[k] < i) {
                        count++;
                    }
                }
                if (count == inv[i - 1]) {
                    pos = j;
                    break;
                }
            }
        }
        perm[pos] = i;
    }
    for (int i = 0; i < N; i++) {
        printf("%d ", perm[i]);
    }
    return 0;
}

