import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();
        int[] inv = new int[N];
        int[] perm = new int[N];
        for (int i = 0; i < N; i++) {
            inv[i] = sc.nextInt();
        }
        for (int i = 1; i <= N; i++) {
            int pos = 0;
            for (int j = 0; j < N; j++) {
                if (perm[j] == 0) {
                    int count = 0;
                    for (int k = j + 1; k < N; k++) {
                        if (perm[k] != 0 && perm[k] < i) {
                            count++;
                        }
                    }
                    if (count == inv[i - 1]) {
                        pos = j;
                        break;
                    }
                }
            }
            perm[pos] = i;
        }
        for (int i = 0; i < N; i++) {
            System.out.print(perm[i] + " ");
